// Extrae el bloque JSON de la respuesta de texto de RC-Brain (puede venir con
// prosa alrededor pese al prompt -- no confiar ciegamente, ver I4).
const text = $input.first().json.answer || '';
const start = text.indexOf('{');
const end = text.lastIndexOf('}');
if (start === -1 || end === -1) {
  throw new Error('RC-Brain no devolvió un JSON de variantes reconocible: ' + text.slice(0, 200));
}
const parsed = JSON.parse(text.slice(start, end + 1));
return [{ json: parsed }];
